declare(strict_types=1);require_once dirname(__DIR__,2).'/includes/comunicacion_centro.php';exigirAutenticacion();$id=filter_var($_GET['id']??0,FILTER_VALIDATE_INT,['options'=>['min_range'=>1]])?:0;$pdo=obtenerConexion();$u=(int)$_SESSION['usuario_id'];$q=$pdo->prepare('SELECT a.*,m.autor_usuario_id,h.usuario_relacionado_id,m.remitente,m.destinatario FROM correo_centro_adjuntos a JOIN correo_centro_mensajes m ON m.id=a.mensaje_id JOIN correo_centro_hilos h ON h.id=m.hilo_id WHERE a.id=:id');$q->execute(['id'=>$id]);$a=$q->fetch();$yo=comunicacionUsuario($pdo,$u);if(!$a||($_SESSION['usuario_rol']!=='admin'&&(int)$a['autor_usuario_id']!==$u&&(int)$a['usuario_relacionado_id']!==$u&&$a['remitente']!==$yo['correo']&&$a['destinatario']!==$yo['correo'])){http_response_code(403);exit('Acceso denegado.');}$ruta=rutaPrivadaComunicacion($a['archivo_relpath']);if(!$ruta){http_response_code(404);exit;}$nombre=preg_replace('/[^A-Za-z0-9._-]/','-',basename($a['archivo_nombre']));header('X-Content-Type-Options: nosniff');header('Cache-Control: private, no-store');header('Content-Type: '.$a['archivo_mime']);header('Content-Length: '.filesize($ruta));header('Content-Disposition: attachment; filename="'.$nombre.'"');readfile($ruta);
